#!/usr/bin/env python3
"""
Generate Core/Src/font.c with four bitmap fonts for OLED text rendering.

Fonts: 8x6, 12x6, 16x8, 16x16
Layout: column-major — for width W, height H, bytes_per_col = ceil(H/8):
  offset = (ch - first) * W * bytes_per_col
  byte at [offset + col * bytes_per_col + row_byte]
  LSB = top pixel of that 8-px band.
"""

import os, sys

# ── Glyph design helpers ────────────────────────────────────────────────────

def make_glyph(width, height, rows_str):
    """
    Convert a multi-line string (rows, '.'=off '#'=on) into column-major bytes.

    rows_str: string with newlines, each line is `width` chars ('.' or '#').
    Pads/clips to exactly `height` rows.
    """
    lines = [l for l in rows_str.split('\n') if l.strip() != '']
    # Pad or clip
    while len(lines) < height:
        lines.append('.' * width)
    lines = lines[:height]

    bytes_per_col = (height + 7) // 8
    result = []
    for col in range(width):
        for rb in range(bytes_per_col):
            byte = 0
            for bit in range(8):
                row = rb * 8 + bit
                if row < height and col < len(lines[row]):
                    if lines[row][col] == '#':
                        byte |= (1 << bit)
            result.append(byte)
    return result


def make_blank(width, height):
    """Return an all-off glyph of given dimensions."""
    bytes_per_col = (height + 7) // 8
    return [0] * (width * bytes_per_col)


