def write_font(f, name, width, height, glyphs, first_char=0x20, last_char=0x7E):
    """Write a single C font to the output file."""
    bytes_per_col = (height + 7) // 8
    stride = width * bytes_per_col
    num_chars = last_char - first_char + 1

    total_expected = num_chars * stride

    # Build flat array
    data = []
    for code in range(first_char, last_char + 1):
        ch = chr(code)
        if ch in glyphs:
            g = make_glyph(width, height, glyphs[ch])
        else:
            g = make_blank(width, height)
        data.extend(g)

    # Write data array
    f.write(f'static const uint8_t {name}_data[] = {{\n')
    per_line = 16
    for i in range(0, len(data), per_line):
        chunk = data[i:i+per_line]
        f.write('    ' + ', '.join(f'0x{b:02X}' for b in chunk) + ',\n')
    f.write('};\n\n')

    # Write FontDef
    f.write(f'const FontDef {name} = {{\n')
    f.write(f'    .data          = {name}_data,\n')
    f.write(f'    .width         = {width}U,\n')
    f.write(f'    .height        = {height}U,\n')
    f.write(f'    .first_char    = 0x{first_char:02X}U,\n')
    f.write(f'    .last_char     = 0x{last_char:02X}U,\n')
    f.write(f'    .bytes_per_col = {bytes_per_col}U\n')
    f.write('};\n\n')


def main():
    out_path = os.path.join(os.path.dirname(__file__), '..', 'Core', 'Src', 'font.c')
    print(f'Generating: {out_path}')

    with open(out_path, 'w', encoding='utf-8') as f:
        f.write('''/**
 ******************************************************************************
 * @file    font.c
 * @brief   Bitmap font data for OLED text rendering (auto-generated).
 *
 * Fonts (column-major layout, 95 printable ASCII glyphs each):
 *   - font8x6   : 8 x6  pixels  (760 bytes)
 *   - font12x6  : 12x6  pixels  (1140 bytes)
 *   - font16x8  : 16x8  pixels  (1520 bytes)
 *   - font16x16 : 16x16 pixels  (3040 bytes)
 ******************************************************************************
 */

#include "oled.h"

''')

        write_font(f, 'font8x6',   8,  6,  G8)
        write_font(f, 'font12x6',  12, 6,  G12)
        write_font(f, 'font16x8',  16, 8,  G16_8)
        write_font(f, 'font16x16', 16, 16, G16_16)

    print('Done.')


if __name__ == '__main__':
    main()
